// Marker → grammar point IDs lookup
export const MARKER_TO_IDS: Record<string, number[]> = {};
for (const gp of GRAMMAR_POINTS) {
  for (const m of gp.markers) {
    if (!MARKER_TO_IDS[m]) MARKER_TO_IDS[m] = [];
    MARKER_TO_IDS[m].push(gp.id);
  }
}

// ID lookup
export const GP_BY_ID: Record<number, GrammarPointDef> = {};
for (const gp of GRAMMAR_POINTS) GP_BY_ID[gp.id] = gp;
